-- ============================================
-- жЁЎжӢҹ1100дҪҚз”ЁжҲ·ж•°жҚ® - е®Ңж•ҙзүҲ
-- з”ЁжҲ·еҗҚ: user0001 ~ user1100
-- еҜҶз Ғ: 123456 (BCryptеҠ еҜҶ)
-- ============================================

-- BCryptеҠ еҜҶеҗҺзҡ„еҜҶз Ғ "123456"
SET @pwd = '$2a$10$7JB720yubVSZvUI0rEqK/.VqGOZTH.ulu33dHOiBE8ByOhJIrdAu2';

-- жҸ’е…Ҙз”ЁжҲ·ж•°жҚ® (еҲҶжү№жү§иЎҢпјҢжҜҸжү№50жқЎ)

-- з¬¬1жү№: user0001 - user0050

-- з¬¬2жү№: user0051 - user0100

-- ============================================
-- жҸ’е…Ҙз”ЁжҲ·и§’иүІе…іиҒ”
-- ============================================
-- дёәжүҖжңүж–°жҸ’е…Ҙзҡ„з”ЁжҲ·еҲҶй…Қжҷ®йҖҡз”ЁжҲ·и§’иүІ(role_id=2)
SELECT user_id, 2 FROM sys_user WHERE user_name LIKE 'user%' AND user_id NOT IN (SELECT user_id FROM sys_user_role WHERE role_id = 2);

-- ============================================
-- йӘҢиҜҒжҸ’е…Ҙз»“жһң
-- ============================================
SELECT 'з”ЁжҲ·жҖ»ж•°:' AS info, COUNT(*) AS count FROM sys_user;
SELECT 'жҷ®йҖҡз”ЁжҲ·и§’иүІе…іиҒ”ж•°:' AS info, COUNT(*) AS count FROM sys_user_role WHERE role_id = 2;
